// n8n Code Node (JavaScript)

// -------------------------------------------------------
// 1) STOPWORDS & JUNKWORDS
// -------------------------------------------------------

// Ein-Wort-Stopwords für Focus-Keywords (aber NICHT "gift"/"gifts")
const STOPWORDS = new Set([
  'for','with','and','the','a','an',
  'new','original','premium','compatible','replacement',
  'include','included','pack','set',
  'tshirt','t-shirts','t-shirt','tee','tees','shirt','shirts', 'clothing',
  // 'gift','gifts',  // WICHTIG: rausgenommen, damit Phrasen wie "school bus gift" möglich sind
  'men','womens','women','girls','boys','kids','kid',
  'child','children','unisex','adult','youth',
  'small','medium','large','xl','xxl','xxxl',
  'color','colours','colour',
  'black','white','blue','red','green','yellow','pink','grey','gray'
]);

// Müllwörter, die nie Fokus sein sollen
const JUNK_WORDS = new Set([
  'amp','nbsp','thy','who','she','he','they','them','their','his','her',
  'our','your','you','all','its','it',
  'co','only','stuff','etc','ive','im','we','us',
  'corner', 'list', 'monitor', 'grammar'
]);

const FUNCTION_WORDS = new Set([
  'am','are','is','was','were','be','been','being',
  'do','does','did','done','doing',
  'have','has','had',
  'can','could','may','might','must','shall','should','will','would',
  'in','on','at','of','to','from','by','for','about','into','over','under',
  'up','down','out','off','than','then','that','this','these','those',
  'as','so','if','because','while','when','where', 'just'
]);

function isJunkWord(word) {
  if (!word) return true;
  if (word.length < 3) return true;
  if (/^\d+$/.test(word)) return true;            // reine Zahlen
  if (/^[a-z]{1,2}$/.test(word)) return true;     // 1–2 Buchstaben
  if (STOPWORDS.has(word)) return true;
  if (JUNK_WORDS.has(word)) return true;
  if (FUNCTION_WORDS.has(word)) return true;
  return false;
}

// -------------------------------------------------------
// 2) LIGHT POS: NOUN-LIKELIHOOD HEURISTIC
// -------------------------------------------------------
function isLikelyNoun(word, freq = 1) {
  if (!word) return false;
  if (isJunkWord(word)) return false;

  const nounSuffixes = [
    'er','or','ist','ism','ment','ness','tion','sion','ity',
    'ship','hood','age','acy','ance','ence','al','ure','ing','gift','lover'
  ];

  let score = 0;

  if (word.length >= 4) score += 0.2;
  if (word.length >= 6) score += 0.1;

  for (const suf of nounSuffixes) {
    if (word.endsWith(suf)) {
      score += 0.4;
      break;
    }
  }

  if (word.includes('-')) score += 0.2;

  if (freq >= 2) score += 0.2;
  if (freq >= 5) score += 0.1;

  if (FUNCTION_WORDS.has(word)) return false;

  return score >= 0.4;
}

// -------------------------------------------------------
// 3) Normalisierung & Tokenisierung
// -------------------------------------------------------
function normalizeText(text) {
  text = (text || '').toLowerCase();
  text = text.replace(/\([^)]*\)/g, ' ');
  text = text.replace(/&[a-z]+;/g, ' ');         // HTML entities (&amp; ...)
  text = text.replace(/[^a-z0-9\s-]/g, ' ');
  text = text.replace(/\s+/g, ' ').trim();
  return text;
}

// Tokens für Fokus-Keywords (aggressiver Filter)
function tokenizeFocus(text) {
  const normalized = normalizeText(text);
  if (!normalized) return [];
  const tokens = normalized.split(' ');
  return tokens.filter(t =>
    t.length > 2 &&
    !/^\d+$/.test(t) &&
    !STOPWORDS.has(t) &&
    !JUNK_WORDS.has(t)
  );
}

// Tokens für Long-Tails: etwas lockerer, damit "gift" etc. drin bleiben
function tokenizeLong(text) {
  const normalized = normalizeText(text);
  if (!normalized) return [];
  const tokens = normalized.split(' ');
  return tokens.filter(t =>
    t.length > 2 &&
    !/^\d+$/.test(t) &&
    !JUNK_WORDS.has(t)   // STOPWORDS dürfen drin bleiben
  );
}

// 2–3-Wort-N-Gramme bauen
function buildNgrams(tokens, minN = 2, maxN = 3) {
  const out = [];
  for (let n = minN; n <= maxN; n++) {
    if (tokens.length < n) continue;
    for (let i = 0; i <= tokens.length - n; i++) {
      out.push(tokens.slice(i, i + n).join(' '));
    }
  }
  return out;
}

// -------------------------------------------------------
// 4) INPUT prüfen
// -------------------------------------------------------
if (!items.length || !items[0].json || !Array.isArray(items[0].json.products)) {
  return [];
}

const entries = items[0].json.products;
if (!entries.length) {
  return [];
}

// -------------------------------------------------------
// 5) Global Frequencies
// -------------------------------------------------------
const allWords = [];
const allNgrams = [];
const perItemData = [];
const docFreqWords = {};
const docFreqNgrams = {};

for (const entry of entries) {
  const brand = entry.brand || '';
  const title = entry.title || '';
  const text = `${brand} ${title}`.trim();

  const focusTokens = tokenizeFocus(text);
  const longTokens  = tokenizeLong(text);

  perItemData.push({ entry, brand, title, focusTokens, longTokens });

  if (!focusTokens.length && !longTokens.length) continue;

  allWords.push(...focusTokens);

  const ngrams = buildNgrams(longTokens, 2, 3);
  allNgrams.push(...ngrams);

  const tokenSet = new Set(focusTokens);
  for (const t of tokenSet) {
    docFreqWords[t] = (docFreqWords[t] || 0) + 1;
  }

  const ngramSet = new Set(ngrams);
  for (const g of ngramSet) {
    docFreqNgrams[g] = (docFreqNgrams[g] || 0) + 1;
  }
}

const wordFreq = {};
for (const w of allWords) wordFreq[w] = (wordFreq[w] || 0) + 1;

const ngramFreq = {};
for (const g of allNgrams) ngramFreq[g] = (ngramFreq[g] || 0) + 1;

const numDocs = Math.max(entries.length, 1);

const GENERIC_WORDS = new Set(
  Object.entries(docFreqWords)
    .filter(([_, df]) => df >= numDocs * 0.8)
    .map(([w]) => w)
);

const GENERIC_NGRAMS = new Set(
  Object.entries(docFreqNgrams)
    .filter(([_, df]) => df >= numDocs * 0.8)
    .map(([g]) => g)
);

// -------------------------------------------------------
// 6) Pro Produkt: Keywords
// -------------------------------------------------------
const perProductResults = [];

for (const { brand, title, focusTokens, longTokens } of perItemData) {
  const seenWords = new Set();
  const uniqueTokens = [];

  for (const t of focusTokens) {
    if (
      !seenWords.has(t) &&
      !GENERIC_WORDS.has(t) &&
      !isJunkWord(t) &&
      isLikelyNoun(t, wordFreq[t] || 1)
    ) {
      seenWords.add(t);
      uniqueTokens.push(t);
    }
  }

  const shortTailSorted = uniqueTokens.sort(
    (a, b) => (wordFreq[b] || 0) - (wordFreq[a] || 0)
  );
  const short_tail_keywords = shortTailSorted.slice(0, 10);

  const ngrams = buildNgrams(longTokens, 2, 3);
  const longCandidates = [];
  const seenNgrams = new Set();

  for (const g of ngrams) {
    if (seenNgrams.has(g) || GENERIC_NGRAMS.has(g)) continue;
    const words = g.split(' ');
    // mind. 2 Worte sollen wie Nomen aussehen
    const nounCount = words.filter(w => isLikelyNoun(w, wordFreq[w] || 1)).length;
    if (nounCount >= 1 && words.every(w => !isJunkWord(w))) {
      seenNgrams.add(g);
      longCandidates.push(g);
    }
  }

  const longTailSorted = longCandidates.sort(
    (a, b) => (ngramFreq[b] || 0) - (ngramFreq[a] || 0)
  );
  const long_tail_keywords = longTailSorted.slice(0, 10);

  perProductResults.push({
    brand,
    title,
    short_tail_keywords,
    long_tail_keywords,
    main_short_tail: short_tail_keywords[0] || "",
    main_long_tail: long_tail_keywords[0] || "",
    all_keywords_flat: [...short_tail_keywords, ...long_tail_keywords],
    short_tail_count: short_tail_keywords.length,
    long_tail_count: long_tail_keywords.length
  });
}

// -------------------------------------------------------
// 7) Globale Top-Listen
// -------------------------------------------------------
const TOP_N = 50;

const top_focus_keywords = Object.entries(wordFreq)
  .filter(([w]) =>
    !GENERIC_WORDS.has(w) &&
    !isJunkWord(w) &&
    isLikelyNoun(w, wordFreq[w] || 1)
  )
  .sort((a, b) => b[1] - a[1])
  .slice(0, TOP_N)
  .map(([keyword, used]) => ({ keyword, used }));

const top_long_tail_keywords = Object.entries(ngramFreq)
  .filter(([g]) => !GENERIC_NGRAMS.has(g))
  .map(([g, count]) => ({ g, words: g.split(" "), count }))
  .filter(o =>
    o.words.every(w => !isJunkWord(w)) &&
    o.words.filter(w => isLikelyNoun(w, wordFreq[w] || 1)).length >= 1
  )
  .sort((a, b) => b.count - a.count)
  .slice(0, TOP_N)
  .map(o => ({ keyword: o.g, used: o.count }));

// -------------------------------------------------------
// 8) Output
// -------------------------------------------------------
return [
  {
    json: {
      products: perProductResults,
      main_short_tail: perProductResults[0].main_short_tail,
      main_long_tail: perProductResults[0].main_long_tail, 
      all_keywords_flat: perProductResults[0].all_keywords_flat,
      top_focus_keywords,
      top_long_tail_keywords
    }
  }
];

// n8n Code Node (JavaScript)
// Input:  item.json.slogan_text (String)
// Output: isSlogan (bool), sloganScore, sloganWordCount, sloganReasons

function classifySloganSimple(text) {
  const info = {
    isSlogan: false,
    sloganScore: 0,
    sloganWordCount: 0,
    sloganReasons: [],
  };

  if (!text || typeof text !== 'string') {
    info.sloganReasons.push('Empty or non-string input');
    return info;
  }

  const raw = text.trim();
  if (!raw) {
    info.sloganReasons.push('Empty after trim');
    return info;
  }

  // Wörter zählen (Newline, Tabs etc. werden auch als Separator behandelt)
  const words = raw.split(/\s+/).filter(Boolean);
  const wordCount = words.length;
  info.sloganWordCount = wordCount;

  const lc = raw.toLowerCase();
  const containsSquadOrCrew = /\b(squad|crew)\b/.test(lc);

  // Regel:
  // - Wenn <= 2 Wörter UND kein "Squad"/"Crew" → KEIN Slogan
  // - Sonst → Slogan
  if (wordCount <= 2 && !containsSquadOrCrew) {
    info.isSlogan = false;
    info.sloganScore = 0;
    info.sloganReasons.push('Rejected: <= 2 words and no "Squad"/"Crew"');
  } else {
    info.isSlogan = true;
    info.sloganScore = 1;
    info.sloganReasons.push('Accepted: length > 2 or contains "Squad"/"Crew"');
  }

  return info;
}

// n8n items verarbeiten
return items.map((item) => {
  const text = item.json.slogan_text;
  const res = classifySloganSimple(text);

  return {
    json: {
      ...item.json,
      isSlogan: res.isSlogan,
      sloganScore: res.sloganScore,
      sloganWordCount: res.sloganWordCount,
      sloganReasons: res.sloganReasons,
    },
  };
});

const item = $input.first();

item.json.top_focus_keywords = item.json.top_focus_keywords.filter(k => k.used > 2);
item.json.top_long_tail_keywords = item.json.top_long_tail_keywords.filter(k => k.used > 2);

return [item];

