const items = $input.all();

// Daten von der Edit Fields Node holen
const editFieldsItems = $('Edit Fields').all();

return items.map((item, index) => {
  const json = item.json;

  // Entsprechendes Item von Edit Fields (gleicher Index)
  const editFieldsData = editFieldsItems[index]?.json;

  return {
    json: {
      // niche_name kommt von Edit Fields Node
      niche_name: editFieldsData?.niche_1 || '',

      // Alle anderen kommen aus LLM Agent Output
      niche_summary: json.output?.niche_summary || '',
      sentiment: json.output?.sentiment || '',
      primary_emotions: json.output?.primary_emotions || [],
      emotional_archetype: json.output?.emotional_archetype || [],
      example_keywords: json.output?.example_keywords || [],
      pattern_analysis: json.output?.pattern_analysis || [],
      emotional_reality: json.output?.emotional_reality || '',
      design_concepts: json.output?.design_concepts || '',
      dominant_design_aesthetics: json.output?.dominant_design_aesthetics || ''
    }
  };
});

// Code Node: Run once for all items

// Nische aus dem ersten Input-Item lesen
const originalNiche = $('Edit Fields').first().json.niche_1;

if (!originalNiche || typeof originalNiche !== 'string') {
  throw new Error('Keine gültige Nische gefunden');
}

// Nische encoden – nur den Suchterm, nicht die ganze URL!
// Beispiel: "Funny Bus Driver" -> "Funny+Bus+Driver"
const encodedNiche = encodeURIComponent(originalNiche)
  .replace(/'/g, '%27')   // Apostroph encoden
  .replace(/%20/g, '+');  // Spaces als + für Amazon

// Basis-Parameter für beide URLs
const baseParams = `k=${encodedNiche}&i=fashion-novelty&rh=p_6%3AATVPDKIKX0DER&s=xyzxyz&hidden-keywords=Lightweight%2C+Classic+fit%2C+Double-needle+sleeve+and+bottom+hem+-Longsleeve+-Raglan+-Vneck+-Tanktop&language=en_US`;

// Amazon-URL Seite 1
const searchUrl = `https://www.amazon.com/s?${baseParams}`;

// Amazon-URL Seite 2 (nur page=2 hinzufügen)
const searchUrlPage2 = `https://www.amazon.com/s?${baseParams}&page=2`;

// Als einzelnes Objekt zurückgeben
return {
  json: {
    url: searchUrl,
    url_page_2: searchUrlPage2,
    niche: originalNiche,
  },
};

const BASE_URL = 'https://www.amazon.com';

// Bereinigung: Entferne problematische Zeichen für JSON-Serialisierung
function cleanText(text) {
  if (!text) return text;

  let cleaned = text.trim();

  // Entferne äußere Quotes
  while (cleaned.startsWith('"') || cleaned.startsWith("'")) {
    cleaned = cleaned.substring(1);
  }
  while (cleaned.endsWith('"') || cleaned.endsWith("'")) {
    cleaned = cleaned.substring(0, cleaned.length - 1);
  }

  // Entferne Backslashes und HTML-Entities
  cleaned = cleaned
    .replace(/\\/g, '')
    .replace(/&quot;/g, '')  // ← Entferne statt ersetzen!
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&apos;/g, "'")
    .replace(/&#x([0-9a-f]+);/gi, (match, hex) => String.fromCharCode(parseInt(hex, 16)))
    .replace(/&#(\d+);/g, (match, dec) => String.fromCharCode(dec))
    .trim();

  // KRITISCH: Entferne alle doppelten Anführungszeichen aus dem finalen String
  cleaned = cleaned.replace(/"/g, '');

  return cleaned;
}

// ASIN aus data-csa-c-item-id oder als Fallback aus /dp/ASIN/
function extractAsin(html) {
  const dataMatch = html.match(/data-csa-c-item-id="amzn1\.asin\.(?:\d\.)?([A-Z0-9]{10})"/i);
  if (dataMatch) return dataMatch[1];

  const dpMatch = html.match(/\/dp\/([A-Z0-9]{10})/i);
  return dpMatch ? dpMatch[1] : null;
}

// ROBUSTE TITEL-EXTRAKTION
function extractTitle(html) {
  let match = html.match(
    /<h2[^>]*class="[^"]*a-size-base-plus[^"]*"[^>]*aria-label="([^"]*(?:\\"[^"]*)*)"[^>]*>/i
  );
  if (match) {
    return cleanText(match[1]);
  }

  match = html.match(
    /<h2[^>]*class="[^"]*a-size-base-plus[^"]*"[^>]*>[\s\S]*?<span[^>]*>([\s\S]*?)<\/span>[\s\S]*?<\/h2>/i
  );
  if (match) {
    const cleaned = match[1]
      .replace(/<[^>]+>/g, '')
      .replace(/\s+/g, ' ')
      .trim();
    return cleanText(cleaned);
  }

  match = html.match(
    /<h2[^>]*class="[^"]*a-size-mini[^"]*"[^>]*>[\s\S]*?<span[^>]*>([\s\S]*?)<\/span>[\s\S]*?<\/h2>/i
  );
  if (match) {
    const cleaned = match[1]
      .replace(/<[^>]+>/g, '')
      .replace(/\s+/g, ' ')
      .trim();
    return cleanText(cleaned);
  }

  return null;
}

// BRAND/SELLER NAME EXTRAKTION
function extractBrand(html) {
  const regexSpan = /<h2[^>]*class="[^"]*a-size-mini[^"]*"[^>]*>[\s\S]*?<span[^>]*class="[^"]*a-size-base-plus a-color-base[^"]*"[^>]*>([\s\S]*?)<\/span>[\s\S]*?<\/h2>/i;

  const spanMatch = html.match(regexSpan);
  if (spanMatch) {
    const cleaned = spanMatch[1]
      .replace(/<[^>]+>/g, '')
      .replace(/\s+/g, ' ')
      .trim();
    return cleanText(cleaned);
  }

  const merchantMatch = html.match(/[&?]m=([^&"]+)/i);
  return merchantMatch ? merchantMatch[1] : null;
}

// URL zur Produktseite (absolute URL, ohne Query)
function extractUrl(html, asin) {
  let urlMatch = null;

  if (asin) {
    const asinRegex = new RegExp(`href="([^"]*\\/dp\\/${asin}[^"]*)"`, 'i');
    urlMatch = html.match(asinRegex);
  }

  if (!urlMatch) {
    urlMatch = html.match(/href="([^"]*\/dp\/[A-Z0-9]{10}[^"]*)"/i);
  }

  if (!urlMatch) return null;

  const url = urlMatch[1];
  const path = url.split('?')[0];

  if (path.startsWith('http')) return path;
  if (path.startsWith('/')) return BASE_URL + path;
  return `${BASE_URL}/${path}`;
}

// Thumbnail (Produktbild, s-image)
function extractThumbnail(html) {
  const match = html.match(/<img[^>]*class="[^"]*s-image[^"]*"[^>]*src="([^"]+)"/i);
  return match ? match[1] : null;
}

// Rating (z.B. "4.8")
function extractRate(html) {
  const match = html.match(
    /data-cy="reviews-block"[\s\S]*?<span[^>]*class="[^"]*a-size-small[^"]*a-color-base[^"]*"[^>]*>([\s\S]*?)<\/span>/i
  );
  if (!match) return null;

  const text = match[1]
    .replace(/<[^>]+>/g, '')
    .trim()
    .replace(',', '.');

  const value = parseFloat(text);
  return Number.isNaN(value) ? null : value;
}

// Review-Count (z.B. "(6)" → 6)
function extractReviewCount(html) {
  const match = html.match(
    /data-cy="reviews-block"[\s\S]*?<span[^>]*class="[^"]*a-size-mini[^"]*"[^>]*>([\s\S]*?)<\/span>/i
  );
  if (!match) return null;

  const text = match[1]
    .replace(/<[^>]+>/g, '')
    .replace(/[()]/g, '')
    .trim();

  const value = parseInt(text, 10);
  return Number.isNaN(value) ? null : value;
}

// Hauptlogik: $input.all() + products[] -> mehrere Items
const output = [];

for (const inputItem of $input.all()) {
  const products = inputItem.json.products || [];

  for (const productHtml of products) {
    const html = String(productHtml || '');

    const asin = extractAsin(html);
    const title = extractTitle(html);
    const brand = extractBrand(html);
    const url = extractUrl(html, asin);
    const thumbnailImage = extractThumbnail(html);
    const rate = extractRate(html);
    const reviewsCount = extractReviewCount(html);
    const niche = $('Edit Fields').first().json.niche_1;

    output.push({
      json: {
        niche,
        asin,
        title,
        brand,
        url,
        rate,
        reviewsCount,
        thumbnailImage,
      },
    });
  }
}

return output;

// Lese den pageCount String
const pageCountText = $json.pageCount;

// Extrahiere die Zahl nach "of" (z.B. 210 aus "1-48 of 210 results")
const match = pageCountText.match(/of\s+(\d+)/i);

if (match) {
  const count = parseInt(match[1]);

  return {
    json: {
      pageCount: count
    }
  };
} else {
  // Fallback: Keine Zahl nach "of" gefunden
  return {
    json: {
      pageCount: 0,
      error: 'Keine Zahl nach "of" gefunden'
    }
  };
}
